<script setup lang="ts">
import { computed,nextTick,onMounted,onUnmounted,ref } from 'vue'; import * as echarts from 'echarts'; import PageHeader from '../components/PageHeader.vue'; import { useAuthStore } from '../stores/auth'; import { getActiveActivity,getRecords } from '../services/api'; import type { ActivityUser,DailyRecord } from '../types'; import { totalLoss } from '../utils/metrics'
const auth=useAuthStore();const el=ref<HTMLElement>();const records=ref<DailyRecord[]>([]);const member=ref<ActivityUser|null>(null);let chart:echarts.ECharts|undefined
const latest=computed(()=>records.value[0]?.weight??member.value?.initial_weight??0);const loss=computed(()=>member.value?totalLoss(member.value.initial_weight,latest.value):0);const weekly=computed(()=>records.value.length>1?+(loss.value/(Math.max(1,(Date.parse(records.value[0].record_date)-Date.parse(records.value.at(-1)!.record_date))/604800000))).toFixed(2):0)
function draw(){if(!el.value||!member.value)return;const rows=[...records.value].reverse();chart=echarts.init(el.value);chart.setOption({grid:{left:42,right:16,top:28,bottom:35},tooltip:{trigger:'axis'},xAxis:{type:'category',data:rows.map(r=>r.record_date.slice(5))},yAxis:{type:'value',scale:true},series:[{type:'line',smooth:true,data:rows.map(r=>r.weight),lineStyle:{color:'#1f765c',width:3},itemStyle:{color:'#1f765c'},markLine:{symbol:'none',data:[{yAxis:member.value.initial_weight,name:'初始'},{yAxis:member.value.target_weight,name:'目标'}]}}]})}
onMounted(async()=>{if(!auth.user)return;const x=await getActiveActivity(auth.user.id);member.value=x.membership;if(x.activity)records.value=await getRecords(auth.user.id,x.activity.id);await nextTick();draw();window.addEventListener('resize',()=>chart?.resize())});onUnmounted(()=>chart?.dispose())
</script>
<template><section class="page"><PageHeader eyebrow="WEIGHT TREND" title="体重趋势" back/><div class="metric-grid"><div class="metric"><small>初始体重</small><b>{{member?.initial_weight||0}}</b></div><div class="metric"><small>最新体重</small><b>{{latest}}</b></div><div class="metric"><small>累计减重</small><b>{{loss}}</b></div><div class="metric"><small>周均减重</small><b>{{weekly}}</b></div></div><div class="card" style="margin-top:14px"><div ref="el" class="chart"></div></div><div class="card row"><span>距离目标</span><strong>{{Math.max(0,latest-(member?.target_weight||latest)).toFixed(1)}} kg</strong></div></section></template>
